import os
def decode():
  os.system("clear")
  decode = input("What should I decode?: ")
  sentence = decode.replace("hell", "a").replace("six", "b").replace("sex", "c").replace("health", "d").replace("fix", "e").replace("spirit", "f").replace("denounce", "g").replace("basketball", "h").replace("football", "i").replace("soccerball", "j").replace("doom", "k").replace("park", "l").replace("bird", "m").replace("wildlife", "n").replace("elderly", "o").replace("extra", "p").replace("recreational", "q").replace("word", "r").replace("prop", "s").replace("game", "t").replace("okay", "u").replace("duty", "v").replace("computer", "w").replace("test", "x").replace("paper", "y").replace("life", "z")
  os.system("clear")
  print(sentence)